def fetch_remote_dependencies():
    """
    Fetches a list of package names (one per line) from a remote URL.
    Handles network errors gracefully.
    """
    print(f"Fetching remote dependencies from: {REMOTE_DEPENDENCY_URL}")
    try:
        # Use urllib.request for built-in HTTP capabilities without external 'requests' dependency
        with urllib.request.urlopen(REMOTE_DEPENDENCY_URL, timeout=10) as response:
            content = response.read().decode('utf-8')
            # Filter out empty lines and comments (lines starting with #)
            dependencies = [line.strip() for line in content.splitlines() if line.strip() and not line.strip().startswith('#')]
            print(f"Successfully fetched dependencies: {dependencies}")
            return dependencies
    except urllib.error.URLError as e:
        print(f"WARNING: Could not fetch remote dependencies due to URL error: {e.reason}")
        print("Falling back to an empty list. Please check your network connection or URL.")
        return []
    except Exception as e:
        print(f"WARNING: An unexpected error occurred while fetching remote dependencies: {e}")
        print("Falling back to an empty list. This might indicate a problem with the remote file or parsing.")
        return []

